const text = $json.text;

let cleanedText = text;

// remove block starting from ADMITO... until CIN...
cleanedText = cleanedText.replace(
  /ADMITO TECHNOLOGIES PRIVATE LIMITED[\s\S]*?CIN:[^\n]*/g,
  ""
);


cleanedText = cleanedText.replace(/\n+/g, "\n")
  .replace(/\s+/g, " ")
  .replace(/_{3,}/g, "")
  .trim();


// get file name and file link from Google Drive Trigger
const fileName = $json.info.Title;
const fileId = $('Download file').item.json.id;
const fileLink = `https://drive.google.com/file/d/${fileId}/view`;


return {
  fileName,
  cleanedText,
  fileId,
  fileLink,
};

const items = $input.all();

const output = [];

for (const item of items) {

  const text = item.json.cleanedText;
  const fileName = item.json.fileName;
  const fileLink = item.json.fileLink;
  const fileId = item.json.fileId;

  output.push({
    json: {
      text: text,
      fileName: fileName,
      fileLink: fileLink,
      fileId: fileId
    }
  });

}

return output;

const staticData = $getWorkflowStaticData('global');

const sessionId = $input.first().json.sessionId;
const chatInput = $input.first().json.chatInput;

if (!staticData.sessions) {
  staticData.sessions = {};
}

if (!staticData.sessions[sessionId]) {
  staticData.sessions[sessionId] = [];
}

return [{
  json: {
    chatInput ,
    sessionId,
    history: staticData.sessions[sessionId]
  }
}];

const metadata = $input.first().json.metadata || {};

const apiKey = metadata.siteKey;
const origin = metadata.origin;

const allowedDomains = [
  "https://logsapp.scaleupally.in",
  "https://logsapp-dev.scaleupally.in",
  "http://localhost:5500",
  "http://127.0.0.1:5500",
  "http://localhost:3000",
  "http://127.0.0.1:3000"
];

if (apiKey !== "SCALEUP_SECRET_2026") {
  return [{ json: { authError: "❌ Invalid API key." } }];
}

if (!allowedDomains.includes(origin)) {
  return [{ json: { authError: "🚫 This chatbot can only be used from the official website." } }];
}

return [{ json: { authError: null, ...$input.first().json } }];

